# JavaScript Debounce 函数

一个经典的 **debounce**（防抖）函数——当事件被连续触发时，只有在最后一次触发后等待指定延迟，才会真正执行回调。

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn      要执行的回调函数
 * @param {number}   delay   延迟时间（毫秒）
 * @param {Object}   options 可选配置
 * @param {boolean}  options.leading  是否在延迟开始前立即执行一次（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  let isLeadingCalled = false;

  const invoke = (type) => {
    if (type === 'leading') {
      isLeadingCalled = true;
      fn.apply(lastThis, lastArgs);
    } else {
      // trailing
      isLeadingCalled = false;
      fn.apply(lastThis, lastArgs);
    }
    lastArgs = null;
    lastThis = null;
  };

  const debounced = function (...args) {
    lastArgs = args;
    lastThis = this;

    // 每次调用清除旧定时器
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    // leading 模式：如果尚未在 leading 执行过一次，立即执行
    if (leading && !isLeadingCalled) {
      invoke('leading');
    }

    // trailing 模式：设置延迟执行
    if (trailing) {
      timer = setTimeout(() => {
        timer = null;
        // 只有当还有待执行的调用时才执行 trailing
        if (lastArgs) {
          invoke('trailing');
        }
      }, delay);
    }
  };

  /**
   * 取消防抖，取消待执行的延迟调用
   */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
    isLeadingCalled = false;
  };

  /**
   * 立即执行并取消防抖
   */
  debounced.flush = function () {
    if (timer && lastArgs) {
      clearTimeout(timer);
      timer = null;
      invoke('trailing');
    }
  };

  return debounced;
}
```

---

## 使用示例

```javascript
// 1. 基本用法（trailing 默认）——输入结束后 500ms 触发
const searchInput = document.querySelector('#search');
searchInput.addEventListener('input', debounce((e) => {
  fetchSearch(e.target.value);
}, 500));

// 2. leading —— 第一次立即执行，然后防抖
const saveBtn = document.querySelector('#save');
saveBtn.addEventListener('click', debounce(() => {
  saveDraft();
}, 3000, { leading: true, trailing: false }));

// 3. 完整 leading + trailing
window.addEventListener('resize', debounce(() => {
  recalcLayout();
}, 200, { leading: true, trailing: true }));

// 4. cancel / flush
const debouncedFn = debounce(() => console.log('hello'), 1000);
debouncedFn();
debouncedFn.cancel(); // 取消待执行的调用

debouncedFn();
debouncedFn.flush();  // 立即执行并清空
```

---

## 核心要点（面试加分 💡）

| 特性 | 说明 |
|------|------|
| **延迟执行（trailing）** | 停止触发后等待 delay 毫秒执行一次 |
| **立即执行（leading）** | 首次触发立即执行，之后防抖期内不执行 |
| **this 绑定** | 正确保留调用上下文（`debounced.apply(ctx, args)`） |
| **cancel / flush** | 提供取消和立即执行的能力，防止内存泄漏 |
| **参数透传** | 事件对象 `event` 等正常传递给回调 |

手写 debounce 是前端面试的**必考题**，重点就是 **`clearTimeout` + `setTimeout` 的配合**，以及 leading/trailing 两种模式的控制。

